import React from 'react'
import '../styles.css'
import styled from "styled-components";
import MealCard from './MealCard';

const MealsContainer = ({meals}) => {
    const m = meals.meals;
    console.log(m)
    return (

    <Wrapper>
        {meals.meals.map((e) => (
        <MealCard {...e} />
        ))}
    </Wrapper>
    );
};

export default MealsContainer

const Wrapper = styled.div`
    display: flex;
    justify-content: space-evenly;
    flex-wrap: wrap;
    padding-top: 50px;
`;
